import { Carousel, CarouselSlide } from '@universe-design/react';
import type { CarouselProps } from '@universe-design/react';
import * as React from 'react';
import { useStyleSheetOnce } from '../../hooks';

export interface CarouselTestDemoBasicProps extends Omit<CarouselProps, 'slides'> {
  slides?: number[];
  injectedStyle?: string;
}

export default ({ injectedStyle = '', slides = [], ...props }: CarouselTestDemoBasicProps) => {
  useStyleSheetOnce(injectedStyle);
  return (
    <Carousel {...props}>
      {slides.map((width, i) => (
        <CarouselSlide fullWidth={false} key={i}>
          <div
            style={{
              boxSizing: 'border-box',
              display: 'inline-flex',
              alignItems: 'center',
              justifyContent: 'center',
              width,
              height: '100%',
            }}
          >
            {i}
          </div>
        </CarouselSlide>
      ))}
    </Carousel>
  );
};
